// BTDropdownMenu — data types.
// Figma: container node 736-1793 · item node 736-1848.
import 'package:flutter/widgets.dart';

/// Discriminates the row kind rendered for each [BTDropdownMenuEntry].
enum BTDropdownMenuEntryType {
  /// Default — interactive action row with label, icons, kbd, subtext.
  item,

  /// Full-width horizontal [BTSeparator] line.
  separator,

  /// Non-interactive section header (12 px, text-secondary).
  group,
}

/// One entry in [BTDropdownMenu.items].
///
/// Use named constructors for separator/group — cleaner call sites:
/// ```dart
/// BTDropdownMenuEntry.separator()
/// BTDropdownMenuEntry.group('Danger zone')
/// BTDropdownMenuEntry(value: 'cut', label: 'Cut', kbd: ['⌘', 'X'])
/// ```
class BTDropdownMenuEntry<T> {
  /// Action item (default).
  const BTDropdownMenuEntry({
    required this.value,
    required this.label,
    this.type = BTDropdownMenuEntryType.item,
    this.subtext,
    this.leftIcon,
    this.rightIcon,
    this.kbd,
    this.disabled = false,
    this.error = false,
  });

  /// Horizontal separator — only [type] is used.
  const BTDropdownMenuEntry.separator()
      : type = BTDropdownMenuEntryType.separator,
        value = null,
        label = null,
        subtext = null,
        leftIcon = null,
        rightIcon = null,
        kbd = null,
        disabled = false,
        error = false;

  /// Section group label — only [type] + [label] are used.
  const BTDropdownMenuEntry.group(String groupLabel)
      : type = BTDropdownMenuEntryType.group,
        value = null,
        label = groupLabel,
        subtext = null,
        leftIcon = null,
        rightIcon = null,
        kbd = null,
        disabled = false,
        error = false;

  final BTDropdownMenuEntryType type;

  /// Returned in [BTDropdownMenu.onSelect]. Null for separator/group.
  final T? value;

  /// Row label or group header text.
  final String? label;

  /// Optional secondary line below [label]. Item only.
  final String? subtext;

  /// 16×16 icon widget left of label. Item only.
  final Widget? leftIcon;

  /// 16×16 icon widget right of label/kbd. Item only.
  final Widget? rightIcon;

  /// Keyboard shortcut keys rendered as [BTKbdGroup]. e.g. ['⌘', 'X'].
  /// Item only.
  final List<String>? kbd;

  /// Renders label in text.disabled and prevents tap. Item only.
  final bool disabled;

  /// Renders label in text.error. Remains tappable unless also [disabled].
  /// Item only.
  final bool error;
}

/// BTDropdownMenu — action menu molecule.
/// Figma: container node 736-1793 · item node 736-1848.
///
/// Pass [items] (flat list of [BTDropdownMenuEntry]) and a [trigger] builder.
/// The floating panel renders via [OverlayPortal] over all other content.
///
/// ## Usage:
/// ```dart
/// BTDropdownMenu<String>(
///   items: const [
///     BTDropdownMenuEntry(value: 'cut',  label: 'Cut',  kbd: ['⌘', 'X']),
///     BTDropdownMenuEntry(value: 'copy', label: 'Copy', kbd: ['⌘', 'C']),
///     BTDropdownMenuEntry.separator(),
///     BTDropdownMenuEntry.group('Danger zone'),
///     BTDropdownMenuEntry(value: 'delete', label: 'Delete', error: true),
///   ],
///   onSelect: (v) => debugPrint('selected: $v'),
///   trigger: ({required toggle, required isOpen}) =>
///     BTButton(label: 'File', onPressed: toggle),
/// )
/// ```
library;

import 'package:btech_ui/src/components/molecules/dropdown_menu/dropdown_menu.types.dart';
import 'package:btech_ui/src/components/molecules/dropdown_menu/internal/dropdown_menu_panel.dart';
import 'package:flutter/material.dart';

typedef BTDropdownMenuTriggerBuilder = Widget Function({
  required VoidCallback toggle,
  required bool isOpen,
});

/// A composable action menu that positions its panel via [OverlayPortal] +
/// [Positioned] with auto-flip (opens above when not enough space below).
class BTDropdownMenu<T> extends StatefulWidget {
  const BTDropdownMenu({
    required this.items,
    required this.trigger,
    this.onSelect,
    this.hasSearch = false,
    this.searchQuery,
    this.onSearchChange,
    this.open,
    this.onOpenChange,
    this.width = 210,
    super.key,
  });

  final List<BTDropdownMenuEntry<T>> items;
  final BTDropdownMenuTriggerBuilder trigger;
  final void Function(T value)? onSelect;
  final bool hasSearch;

  /// Controlled search query. When null, component manages it internally.
  final String? searchQuery;
  final void Function(String query)? onSearchChange;

  /// Controlled open state. When null, component manages it internally.
  final bool? open;
  final void Function({required bool open})? onOpenChange;

  /// Panel width in dp. Default: 210.
  final double width;

  @override
  State<BTDropdownMenu<T>> createState() => _BTDropdownMenuState<T>();
}

// Overhead (dp) subtracted from available space when computing items maxHeight.
// 8 = 4 top + 4 bottom padding inside the panel.
const _kPanelVertPad = 8.0;
// Approximate height of BTInputSearch + 4dp gap below it.
const _kSearchBarH = 54.0;
// Natural max panel height (items 240 + padding 8).
const _kMaxPanelH = 248.0;
// Gap between trigger edge and panel edge.
const _kGap = 4.0;

class _BTDropdownMenuState<T> extends State<BTDropdownMenu<T>> {
  final _overlayController = OverlayPortalController();
  final _triggerKey        = GlobalKey();
  late final Object _tapGroupId = UniqueKey();
  String _localQuery       = '';

  bool get _isOpen => _overlayController.isShowing;

  String get _effectiveQuery => widget.searchQuery ?? _localQuery;

  void _open() {
    if (_isOpen) return;
    // Only reset the local query in uncontrolled search mode.
    if (widget.searchQuery == null) setState(() => _localQuery = '');
    _overlayController.show();
    widget.onOpenChange?.call(open: true);
  }

  void _close() {
    if (!_isOpen) return;
    _overlayController.hide();
    widget.onOpenChange?.call(open: false);
  }

  void _toggle() => _isOpen ? _close() : _open();

  void _handleSelect(T value) {
    widget.onSelect?.call(value);
    _close();
  }

  void _handleSearch(String q) {
    if (widget.onSearchChange != null) {
      widget.onSearchChange!(q);
    } else {
      setState(() => _localQuery = q);
    }
  }

  @override
  void didUpdateWidget(BTDropdownMenu<T> old) {
    super.didUpdateWidget(old);
    // Sync controlled open state
    if (widget.open != null && widget.open != old.open) {
      widget.open! ? _open() : _close();
    }
  }

  @override
  Widget build(BuildContext context) {
    return OverlayPortal(
      controller: _overlayController,
      overlayChildBuilder: (ctx) {
        final box = _triggerKey.currentContext?.findRenderObject() as RenderBox?;
        if (box == null || !box.hasSize) return const SizedBox.shrink();

        final triggerPos    = box.localToGlobal(Offset.zero);
        final triggerWidth  = box.size.width;
        final triggerHeight = box.size.height;
        final screen        = MediaQuery.of(ctx).size;

        // ── Vertical flip ──────────────────────────────────────────────────
        final spaceBelow = screen.height - (triggerPos.dy + triggerHeight) - _kGap;
        final spaceAbove = triggerPos.dy - _kGap;
        final showAbove  = spaceBelow < _kMaxPanelH && spaceAbove > spaceBelow;

        final effectiveMaxH = showAbove
            ? spaceAbove.clamp(80.0, _kMaxPanelH)
            : spaceBelow.clamp(80.0, _kMaxPanelH);

        final overhead  = _kPanelVertPad + (widget.hasSearch ? _kSearchBarH : 0);
        final itemsMaxH = (effectiveMaxH - overhead).clamp(80.0, 240.0);

        final top    = showAbove ? null : triggerPos.dy + triggerHeight + _kGap;
        final bottom = showAbove ? screen.height - triggerPos.dy + _kGap : null;

        // ── Horizontal alignment: start edge (logical) ────────────────────
        final isRtl = Directionality.of(context) == TextDirection.rtl;
        final left  = isRtl ? null : triggerPos.dx;
        final right = isRtl ? screen.width - triggerPos.dx - triggerWidth : null;

        return Stack(
          children: [
            Positioned(
              left:   left,
              right:  right,
              top:    top,
              bottom: bottom,
              child: TapRegion(
                groupId:      _tapGroupId,
                onTapOutside: (_) => _close(),
                child: BTDropdownMenuPanel<T>(
                  items:          widget.items,
                  width:          widget.width,
                  hasSearch:      widget.hasSearch,
                  searchQuery:    _effectiveQuery,
                  onSearchChange: _handleSearch,
                  onSelect:       _handleSelect,
                  maxHeight:      itemsMaxH,
                ),
              ),
            ),
          ],
        );
      },
      child: TapRegion(
        groupId: _tapGroupId,
        child: KeyedSubtree(
          key: _triggerKey,
          child: widget.trigger(toggle: _toggle, isOpen: _isOpen),
        ),
      ),
    );
  }
}

// Internal item-row widget for BTDropdownMenu — not re-exported by the barrel.
// CLAUDE.md §12: no AnimatedContainer — use setState + plain Container.

import 'package:btech_tokens/btech_tokens.dart';
import '../../kbd/kbd.widget.dart';
import 'package:btech_ui/src/components/molecules/dropdown_menu/dropdown_menu.types.dart';
import 'package:flutter/material.dart';

class BTDropdownMenuItemRow<T> extends StatefulWidget {
  const BTDropdownMenuItemRow({
    required this.entry,
    required this.onSelect,
    super.key,
  });

  final BTDropdownMenuEntry<T> entry;
  final void Function(T) onSelect;

  @override
  State<BTDropdownMenuItemRow<T>> createState() =>
      _BTDropdownMenuItemRowState<T>();
}

class _BTDropdownMenuItemRowState<T>
    extends State<BTDropdownMenuItemRow<T>> {
  bool _isHovered = false;
  bool _isPressed = false;

  bool get _disabled => widget.entry.disabled;

  @override
  Widget build(BuildContext context) {
    final c     = context.btColor;
    final entry = widget.entry;

    // Text color: disabled > error > primary
    final textColor = _disabled
        ? c.text.disabled
        : (entry.error ? c.text.error : c.text.primary);

    // Background: only for non-disabled hover/press
    final bg = (!_disabled && (_isHovered || _isPressed))
        ? c.bg.secondary
        : Colors.transparent;

    return MouseRegion(
      cursor: _disabled
          ? SystemMouseCursors.forbidden
          : SystemMouseCursors.click,
      onEnter: _disabled ? null : (_) => setState(() => _isHovered = true),
      onExit:  _disabled ? null : (_) => setState(() => _isHovered = false),
      child: GestureDetector(
        onTapDown: _disabled
            ? null
            : (_) => setState(() => _isPressed = true),
        onTapUp: _disabled
            ? null
            : (_) => setState(() => _isPressed = false),
        onTapCancel: _disabled
            ? null
            : () => setState(() => _isPressed = false),
        onTap: (_disabled || entry.value == null)
            ? null
            : () => widget.onSelect(entry.value as T),
        child: Container(
          decoration: BoxDecoration(
            color:        bg,
            borderRadius: BorderRadius.circular(BTRadius.sm),
          ),
          padding: EdgeInsets.all(8.0),
          child: Row(
            children: [
              // Left icon
              if (entry.leftIcon != null) ...[
                SizedBox(
                  width: 16.0,
                  height: 16.0,
                  child: IconTheme(
                    data: IconThemeData(size: 16, color: textColor),
                    child: entry.leftIcon!,
                  ),
                ),
                SizedBox(width: 4.0),
              ],
              // Label + subtext
              Expanded(
                child: Column(
                  crossAxisAlignment: CrossAxisAlignment.start,
                  mainAxisSize: MainAxisSize.min,
                  children: [
                    Text(
                      entry.label ?? '',
                      style: TextStyle(
                        fontSize: 14.0,
                        fontWeight: FontWeight.w500,
                        fontFamily: BTTypography.fontFamily,
                        color: textColor,
                        height: 16 / 14,
                      ),
                    ),
                    if (entry.subtext != null)
                      Text(
                        entry.subtext!,
                        style: TextStyle(
                          fontSize: 12.0,
                          fontWeight: FontWeight.w500,
                          fontFamily: BTTypography.fontFamily,
                          color: c.text.secondary,
                          height: 16 / 12,
                        ),
                      ),
                  ],
                ),
              ),
              // Kbd group
              if (entry.kbd != null && entry.kbd!.isNotEmpty) ...[
                SizedBox(width: 4.0),
                BTKbdGroup(keys: entry.kbd!),
              ],
              // Right icon
              if (entry.rightIcon != null) ...[
                SizedBox(width: 4.0),
                SizedBox(
                  width: 16.0,
                  height: 16.0,
                  child: IconTheme(
                    data: IconThemeData(size: 16, color: textColor),
                    child: entry.rightIcon!,
                  ),
                ),
              ],
            ],
          ),
        ),
      ),
    );
  }
}

// Internal panel widget for BTDropdownMenu — not re-exported by the barrel.

import 'package:btech_tokens/btech_tokens.dart';
import '../../separator/separator.widget.dart';
import 'package:btech_ui/src/components/molecules/dropdown_menu/dropdown_menu.types.dart';
import 'package:btech_ui/src/components/molecules/dropdown_menu/internal/dropdown_menu_item_row.dart';
import '../../input-search/input_search.widget.dart';
import 'package:flutter/material.dart';

class BTDropdownMenuPanel<T> extends StatelessWidget {
  const BTDropdownMenuPanel({
    required this.items,
    required this.width,
    required this.hasSearch,
    required this.searchQuery,
    required this.onSearchChange,
    required this.onSelect,
    this.maxHeight = 240.0,
    super.key,
  });

  final List<BTDropdownMenuEntry<T>> items;
  final double width;
  final bool hasSearch;
  final String searchQuery;
  final void Function(String) onSearchChange;
  final void Function(T) onSelect;

  /// Maximum height of the scrollable items area. Defaults to 240.
  final double maxHeight;

  @override
  Widget build(BuildContext context) {
    final c = context.btColor;
    return Material(
      color: Colors.transparent,
      child: Container(
        width: width,
        decoration: BoxDecoration(
          color: c.bg.primary,
          borderRadius: BorderRadius.circular(BTRadius.xs),
          boxShadow: const [
            BoxShadow(
              color: Color(0x0F000000),
              blurRadius: 3,
              offset: Offset(0, 4),
            ),
            BoxShadow(
              color: Color(0x0F000000),
              blurRadius: 2,
              offset: Offset(0, 2),
            ),
          ],
        ),
        child: Padding(
          padding: EdgeInsets.all(4.0),
          child: Column(
            mainAxisSize: MainAxisSize.min,
            crossAxisAlignment: CrossAxisAlignment.stretch,
            children: [
              if (hasSearch) ...[
                BTInputSearch(
                  value: searchQuery,
                  onChanged: onSearchChange,
                ),
                SizedBox(height: 4.0),
              ],
              ConstrainedBox(
                constraints: BoxConstraints(maxHeight: maxHeight),
                child: SingleChildScrollView(
                  child: Column(
                    mainAxisSize: MainAxisSize.min,
                    crossAxisAlignment: CrossAxisAlignment.stretch,
                    children: items
                        .map((e) => _buildEntry(context, e))
                        .toList(),
                  ),
                ),
              ),
            ],
          ),
        ),
      ),
    );
  }

  Widget _buildEntry(BuildContext context, BTDropdownMenuEntry<T> entry) {
    final c = context.btColor;
    switch (entry.type) {
      case BTDropdownMenuEntryType.separator:
        return Padding(
          padding: EdgeInsets.symmetric(vertical: 4.0),
          child: const BTSeparator(),
        );

      case BTDropdownMenuEntryType.group:
        return Padding(
          padding: EdgeInsets.symmetric(horizontal: 8.0, vertical: 8.0),
          child: Text(
            entry.label ?? '',
            style: TextStyle(
              fontSize: 12.0,
              fontWeight: FontWeight.w500,
              fontFamily: BTTypography.fontFamily,
              color: c.text.secondary,
              height: 16 / 12,
            ),
          ),
        );

      case BTDropdownMenuEntryType.item:
        return BTDropdownMenuItemRow<T>(
          key: ValueKey('${entry.value}|${entry.label ?? ''}'),
          entry: entry,
          onSelect: onSelect,
        );
    }
  }
}
